mapper.select:
SELECT COALESCE(MAX(sort_order), 0) + 1
FROM trip_schedule
WHERE trip_day_id = #{tripDayId}

SELECT trip_schedule_id, trip_day_id, attraction_no, title, memo, sort_order
FROM trip_schedule
WHERE trip_schedule_id = #{tripScheduleId}

SELECT EXISTS(
    SELECT 1
    FROM trip_day
    WHERE trip_day_id = #{tripDayId}
        AND trip_id = #{tripId}
)
